import { describe, expect, it } from 'vitest';

import {
  AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE,
  SpectralNoiseMonitor,
  TOWER_CEILINGS,
  actionFace,
  classifySpectralNoise,
  classifyMeshAttentionClosure,
  clinamenContract,
  clinamenLift,
  cyclePermute,
  entropyFace,
  estimateMeshAttentionClosureSavedWork,
  fingerprintBuleyProjection,
  governanceSelfSimilarityViolation,
  reduceTraceFingerprint,
  requestEntropy,
  selfSimilarityViolation,
  vacuumBuleyProjection,
  wasteFace,
  type BuleyFace,
  type BuleyProjection,
  type LayerNodeTrace,
} from '../src/spectral-noise-monitor';

function trace(overrides: Partial<LayerNodeTrace> = {}): LayerNodeTrace {
  return {
    requestId: 'req-1',
    nodeIdx: 0,
    chunkIdx: 0,
    startPos: 0,
    sequenceLength: 4,
    latencyMs: 10,
    expectedLatencyMs: 10,
    requestEntropy: 2,
    boundaryLimit: 8,
    timestamp: 1_000,
    ...overrides,
  };
}

describe('spectral noise monitor', () => {
  it('reduces trace latency into finite spectral fingerprints', () => {
    expect(reduceTraceFingerprint(trace({ latencyMs: 5 })).color).toBe('white');
    expect(reduceTraceFingerprint(trace({ latencyMs: 10 })).color).toBe('pink');
    expect(reduceTraceFingerprint(trace({ latencyMs: 20 })).color).toBe(
      'brown'
    );
  });

  it('classifies repeated magnitude-two traces below entropy boundary as pre-collapse', () => {
    const assessment = classifySpectralNoise(trace({ latencyMs: 20 }), [
      { color: 'brown', lowBand: 4, highBand: 1, slopeMagnitude: 2 },
      { color: 'brown', lowBand: 4, highBand: 1, slopeMagnitude: 2 },
    ]);

    expect(assessment.state).toBe('pre_collapse');
    expect(assessment.action).toBe('recommend_reshard');
    expect(assessment.fingerprintBuley).toEqual({
      waste: 4,
      opportunity: 1,
      diversity: 2,
      score: 7,
    });
    expect(assessment.governanceViolation).toEqual({
      ceiling: TOWER_CEILINGS.hexon,
      score: 7,
      correctiveContractCount: 1,
    });
  });

  it('classifies entropy overflow as boundary collapse', () => {
    const assessment = classifySpectralNoise(
      trace({ requestEntropy: 9, boundaryLimit: 8 }),
      []
    );

    expect(assessment.state).toBe('boundary_collapse');
    expect(assessment.action).toBe('recommend_recovery');
  });

  it('emits log-only recommendations without mutating the assessment stream', () => {
    const logged: string[] = [];
    const monitor = new SpectralNoiseMonitor({
      expectedLatencyMs: 10,
      preCollapseWindow: 2,
      log: (assessment) => logged.push(assessment.action),
    });

    monitor.ingest({
      requestId: 'req-1',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 4,
      latencyMs: 20,
      requestEntropy: requestEntropy(4, 0),
      timestamp: 1_000,
    });
    monitor.ingest({
      requestId: 'req-1',
      nodeIdx: 0,
      chunkIdx: 1,
      startPos: 4,
      sequenceLength: 4,
      latencyMs: 20,
      requestEntropy: requestEntropy(4, 0),
      timestamp: 1_001,
    });

    expect(monitor.getAssessments().map((a) => a.state)).toEqual([
      'normal_carrier',
      'pre_collapse',
    ]);
    expect(logged).toEqual(['recommend_reshard']);
  });

  it('classifies the full three-state mesh path from carrier to collapse', () => {
    const monitor = new SpectralNoiseMonitor({
      expectedLatencyMs: 10,
      boundaryLimit: 3,
      preCollapseWindow: 2,
    });

    const normal = monitor.ingest({
      requestId: 'req-1',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 4,
      latencyMs: 5,
      requestEntropy: 2,
      timestamp: 1_000,
    });
    const warmBrown = monitor.ingest({
      requestId: 'req-1',
      nodeIdx: 0,
      chunkIdx: 1,
      startPos: 4,
      sequenceLength: 4,
      latencyMs: 20,
      requestEntropy: 2,
      timestamp: 1_001,
    });
    const preCollapse = monitor.ingest({
      requestId: 'req-1',
      nodeIdx: 0,
      chunkIdx: 2,
      startPos: 8,
      sequenceLength: 4,
      latencyMs: 20,
      requestEntropy: 2,
      timestamp: 1_002,
    });
    const boundaryCollapse = monitor.ingest({
      requestId: 'req-1',
      nodeIdx: 0,
      chunkIdx: 3,
      startPos: 12,
      sequenceLength: 4,
      latencyMs: 20,
      requestEntropy: 9,
      boundaryLimit: 3,
      timestamp: 1_003,
    });

    expect([
      normal.state,
      warmBrown.state,
      preCollapse.state,
      boundaryCollapse.state,
    ]).toEqual([
      'normal_carrier',
      'normal_carrier',
      'pre_collapse',
      'boundary_collapse',
    ]);
    expect([
      normal.action,
      warmBrown.action,
      preCollapse.action,
      boundaryCollapse.action,
    ]).toEqual(['none', 'none', 'recommend_reshard', 'recommend_recovery']);
    expect(normal.buley).toEqual({
      waste: 0,
      opportunity: 1,
      diversity: 1,
      score: 2,
    });
    expect(boundaryCollapse.buley.waste).toBeGreaterThan(0);
  });

  it('vacuum BuleyProjection has zero score on every face', () => {
    expect(vacuumBuleyProjection).toEqual({
      waste: 0,
      opportunity: 0,
      diversity: 0,
      score: 0,
    });
  });

  it('clinamen lift increments the score by exactly one on every face', () => {
    const faces: BuleyFace[] = ['waste', 'opportunity', 'diversity'];
    for (const face of faces) {
      const lifted = clinamenLift(vacuumBuleyProjection, face);
      expect(lifted.score).toBe(1);
      expect(lifted[face]).toBe(1);
    }
  });

  it('lift then contract round-trips on every face (the breathing identity)', () => {
    const seed = clinamenLift(
      clinamenLift(vacuumBuleyProjection, 'waste'),
      'opportunity'
    );
    const faces: BuleyFace[] = ['waste', 'opportunity', 'diversity'];
    for (const face of faces) {
      const breathed = clinamenContract(clinamenLift(seed, face), face);
      expect(breathed).toEqual(seed);
    }
  });

  it('vacuum + 7 clinamen lifts reach a Bule unit with score 7', () => {
    let b = vacuumBuleyProjection;
    b = clinamenLift(b, 'waste');
    b = clinamenLift(b, 'waste');
    b = clinamenLift(b, 'opportunity');
    b = clinamenLift(b, 'opportunity');
    b = clinamenLift(b, 'opportunity');
    b = clinamenLift(b, 'diversity');
    b = clinamenLift(b, 'diversity');
    expect(b).toEqual({ waste: 2, opportunity: 3, diversity: 2, score: 7 });
  });

  it('contract on a zero face stays at zero (Nat-safe)', () => {
    const contracted = clinamenContract(vacuumBuleyProjection, 'waste');
    expect(contracted).toEqual(vacuumBuleyProjection);
  });

  it('three physics faces decompose the Bule unit', () => {
    const b: BuleyProjection = {
      waste: 4,
      opportunity: 5,
      diversity: 6,
      score: 15,
    };
    const w = wasteFace(b);
    const a = actionFace(b);
    const e = entropyFace(b);
    expect(w.score + a.score + e.score).toBe(b.score);
    expect(w).toEqual({ waste: 4, opportunity: 0, diversity: 0, score: 4 });
    expect(a).toEqual({ waste: 0, opportunity: 5, diversity: 0, score: 5 });
    expect(e).toEqual({ waste: 0, opportunity: 0, diversity: 6, score: 6 });
  });

  it('clinamen lifts commute on distinct faces (conservation law)', () => {
    const b: BuleyProjection = {
      waste: 1,
      opportunity: 2,
      diversity: 3,
      score: 6,
    };
    const faces: BuleyFace[] = ['waste', 'opportunity', 'diversity'];
    for (const f of faces) {
      for (const g of faces) {
        const fg = clinamenLift(clinamenLift(b, f), g);
        const gf = clinamenLift(clinamenLift(b, g), f);
        expect(fg).toEqual(gf);
      }
    }
  });

  it('cycle-permute returns to identity after three steps and preserves score', () => {
    const b: BuleyProjection = {
      waste: 1,
      opportunity: 2,
      diversity: 3,
      score: 6,
    };
    const once = cyclePermute(b);
    const twice = cyclePermute(once);
    const thrice = cyclePermute(twice);
    expect(once.score).toBe(b.score);
    expect(twice.score).toBe(b.score);
    expect(thrice).toEqual(b);
  });

  it('maps saturated brown fingerprints to one contract over the Hexon ceiling', () => {
    const brown = reduceTraceFingerprint(trace({ latencyMs: 20 }));

    expect(fingerprintBuleyProjection(brown)).toEqual({
      waste: 4,
      opportunity: 1,
      diversity: 2,
      score: 7,
    });
    expect(governanceSelfSimilarityViolation(brown)).toEqual({
      ceiling: TOWER_CEILINGS.hexon,
      score: 7,
      correctiveContractCount: 1,
    });
  });

  it('keeps pink fingerprints inside the two-head Hexon ceiling', () => {
    const pink = reduceTraceFingerprint(trace({ latencyMs: 10 }));

    expect(fingerprintBuleyProjection(pink)).toEqual({
      waste: 2,
      opportunity: 1,
      diversity: 1,
      score: 4,
    });
    expect(governanceSelfSimilarityViolation(pink)).toBeNull();
  });

  it('self-similarity violation: Trihexon-pressure in Hexon manifold needs 12 contracts', () => {
    const trihexonPressure: BuleyProjection = {
      waste: 18,
      opportunity: 0,
      diversity: 0,
      score: 18,
    };
    const violation = selfSimilarityViolation(
      trihexonPressure,
      TOWER_CEILINGS.hexon
    );
    expect(violation).toEqual({
      ceiling: 6,
      score: 18,
      correctiveContractCount: 12,
    });
  });

  it('self-similarity violation: Hexon-pressure in Triton manifold needs 3 contracts', () => {
    const hexonPressure: BuleyProjection = {
      waste: 6,
      opportunity: 0,
      diversity: 0,
      score: 6,
    };
    const violation = selfSimilarityViolation(
      hexonPressure,
      TOWER_CEILINGS.triton
    );
    expect(violation).toEqual({
      ceiling: 3,
      score: 6,
      correctiveContractCount: 3,
    });
  });

  it('topologically safe: a Bule unit at the manifold ceiling is not a violation', () => {
    const safe: BuleyProjection = {
      waste: 6,
      opportunity: 0,
      diversity: 0,
      score: 6,
    };
    expect(selfSimilarityViolation(safe, TOWER_CEILINGS.hexon)).toBeNull();
  });

  it('inside manifold: a Bule unit below the ceiling is not a violation', () => {
    const small: BuleyProjection = {
      waste: 1,
      opportunity: 1,
      diversity: 1,
      score: 3,
    };
    expect(selfSimilarityViolation(small, TOWER_CEILINGS.hexon)).toBeNull();
  });

  it('string-theory dimension signatures match the Lean tower witnesses', () => {
    // Mirror of Gnosis.BraidedTower.{decagon_in_tower, hendecagon_in_tower,
    // bosonic_string_in_tower}. Signatures, not derivations.
    expect(TOWER_CEILINGS.decagon).toBe(10);
    expect(TOWER_CEILINGS.hendecagon).toBe(11);
    expect(TOWER_CEILINGS.bosonicString).toBe(26);
  });

  it('classifies mesh attention closure using the Aether resolution lift', () => {
    const assessment = classifyMeshAttentionClosure({
      heads: 8,
      observerResolution: TOWER_CEILINGS.dodecagon,
    });

    expect(assessment.observed.headTrace).toEqual([3, 6, 9, 0, 3, 6, 9, 0]);
    expect(assessment.observed.unresolvedResidue).toBe(12);
    expect(assessment.action).toBe('lift_resolution');
    expect(assessment.workPolicy).toMatchObject({
      preserveHeads: true,
      allowHeadPruning: false,
      allowSpeculativeDecode: false,
      allowStandingWaveCompression: false,
      speculativeDepthLimit: 1,
      telemetryLabel: 'attention_closure_lift_required',
    });
    expect(assessment.workPolicy.theoremLineage).toEqual(
      AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
    );
    expect(assessment.decision.after.headTrace).toEqual([
      3, 6, 9, 12, 15, 18, 21, 0,
    ]);
    expect(assessment.decision.after.kind).toBe('structured_signal');
  });

  it('attaches closure lift decisions to monitor assessments when configured', () => {
    const monitor = new SpectralNoiseMonitor({
      expectedLatencyMs: 10,
      attentionClosure: { heads: 8 },
    });

    const assessment = monitor.ingest({
      requestId: 'req-closure',
      nodeIdx: 0,
      chunkIdx: 0,
      startPos: 0,
      sequenceLength: 4,
      latencyMs: 10,
      requestEntropy: 2,
      timestamp: 2_000,
    });

    expect(assessment.attentionClosure?.observed.kind).toBe('aliased_noise');
    expect(assessment.attentionClosure?.action).toBe('lift_resolution');
    expect(assessment.attentionClosure?.workPolicy.allowHeadPruning).toBe(
      false
    );
    expect(assessment.attentionClosure?.workPolicy.theoremLineage).toEqual(
      AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE
    );
    expect(assessment.attentionClosure?.decision.after.unresolvedResidue).toBe(
      0
    );
  });

  it('benchmarks avoided optimizer work for closure-gated distributed traces', () => {
    const assessment = classifyMeshAttentionClosure({
      heads: 8,
      observerResolution: TOWER_CEILINGS.dodecagon,
      requestedSpeculativeDepth: 8,
    });
    const estimate = estimateMeshAttentionClosureSavedWork(
      assessment.workPolicy,
      {
        hiddenDim: 5376,
        batchSize: 2,
        layerCount: 34,
        standingCount: 1612,
        requestedSpeculativeDepth: 8,
        speculativeCandidates: 16,
        headPruneCandidates: 8,
        headDim: 672,
      }
    );

    expect(estimate.gatedOptimizerUnits).toBe(0);
    expect(estimate.avoidedOptimizerUnits).toBeGreaterThan(0);
    expect(estimate.avoidedSpeculativeUnits).toBe(128);
    expect(estimate.preservedHeadPruneUnits).toBe(5376);
    expect(estimate.fullRouteBytesWhenLifted).toBeGreaterThan(
      estimate.compressedRouteBytesIfStable
    );
  });
});
